  var so=document.getElementById('searchOverlay'),si=document.getElementById('searchOverlayInput'),sr=document.getElementById('searchResults'),sb=document.getElementById('searchBtn');
  function ns(s){return s.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');}
  function ps(q){
    if(!sr||!q||q.length<2){if(sr)sr.innerHTML='';return;}
    var query=ns(q);
    var r=biographies.filter(function(b){return ns(b.name).includes(query)||ns(b.profession).includes(query)||(b.tags||[]).some(function(t){return ns(t).includes(query);});});
    if(r.length===0){sr.innerHTML='<div class="search-result-item" style="padding:1.5rem;text-align:center;color:#999">No results</div>';return;}
    try{var sc=JSON.parse(localStorage.getItem('bioSearchCount')||'{}');r.forEach(function(b){var sid=b.id||'';if(sid)sc[sid]=(sc[sid]||0)+1;});localStorage.setItem('bioSearchCount',JSON.stringify(sc));}catch(e){}
    sr.innerHTML=r.slice(0,15).map(function(b){var em={singer:'🎵',actor:'🎬',footballer:'⚽',politician:'🏛️',journalist:'📰',boxer:'🥊',cyclist:'🚴',tennis:'🎾',basketball:'🏀',baseball:'⚾',comedian:'😂',model:'👗',business:'💼',director:'🎥',tech:'💻',writer:'✍️',tv:'📺',chef:'🍳',sports:'🏆',influencer:'📱'};var p=b.profession.toLowerCase();var ic='📌';for(var k in em){if(p.indexOf(k)!=-1){ic=em[k];break;}}var prefix=window.location.pathname.indexOf('/bios/')!=-1?'../':'';return '<a href="'+prefix+b.url+'" class="search-result-item"><div class="search-result-icon">'+ic+'</div><div class="search-result-info"><div class="result-name">'+b.name+'</div><div class="result-profession">'+(b.profession||'')+'</div></div></a>';}).join('');
  }
  if(si)si.addEventListener('input',function(){ps(this.value);});
  if(sb)sb.addEventListener('click',function(){if(so)so.classList.add('active');if(si)si.focus();});
  var hsi=document.getElementById('headerSearchInput');
  if(hsi)hsi.addEventListener('focus',function(){if(so)so.classList.add('active');if(si)si.focus();});
  if(so)so.addEventListener('click',function(e){if(e.target===so)so.classList.remove('active');});
  document.addEventListener('keydown',function(e){if((e.metaKey||e.ctrlKey)&&e.key==='k'){e.preventDefault();if(so)so.classList.add('active');if(si)si.focus();}if(e.key==='Escape'&&so)so.classList.remove('active');});
  // Bio grid pagination
  var bg2=document.getElementById('bioGrid');
  if(bg2){var allC=bg2.querySelectorAll('.bio-card');var totalC=allC.length;var initB=20;var incB=15;var curC=initB;var smBtn=document.getElementById('showMoreBios');var smCount=document.getElementById('showMoreCount');
  function hideBios(c){allC.forEach(function(card,i){if(i<c){card.classList.remove('bio-hidden');}else{card.classList.add('bio-hidden');}});if(smCount){smCount.textContent='Mostrando '+Math.min(c,totalC)+' de '+totalC;}if(smBtn){if(c>=totalC){smBtn.style.display='none';if(smCount)smCount.style.display='none';}else{smBtn.style.display='';if(smCount)smCount.style.display='';}}}
  hideBios(curC);if(smBtn){smBtn.addEventListener('click',function(){curC+=incB;hideBios(curC);});}}
  // Trending
  var tg=document.getElementById('trendingGrid'),bg=document.getElementById('bioGrid');
  if(tg&&bg){try{var c=JSON.parse(localStorage.getItem('bioSearchCount')||'{}');var s=Object.keys(c).sort(function(a,b){return(c[b]||0)-(c[a]||0);});var t=s.slice(0,3);if(t.length<3){t=['shakira','karol-g','maluma'];}var cnt=0;t.forEach(function(sl){try{var card=bg.querySelector('a[href*="'+sl+'.html"]');if(card){var cl=card.cloneNode(true);cl.classList.remove('bio-hidden');tg.appendChild(cl);cnt++;}}catch(e2){}});if(cnt===0){for(var i=0;i<Math.min(3,bg.children.length);i++){var cl=bg.children[i].cloneNode(true);cl.classList.remove('bio-hidden');tg.appendChild(cl);}}}catch(e){}}
